import json, pandas as pd
with open('data/fees.json') as f:
    fees = json.load(f)
mcc=5942
fraud_rate=10.31
total_vol=113260.42

def parse_num(x):
    x=x.strip()
    if x.endswith('%'): return float(x[:-1])
    if x.endswith('k'): return float(x[:-1])*1e3
    if x.endswith('m'): return float(x[:-1])*1e6
    return float(x)
def in_range(val, rng):
    if rng is None: return True
    if '-' in rng and not rng.startswith('-'):
        a,b=rng.split('-')
        return parse_num(a)<=val<=parse_num(b)
    if rng.startswith('>'): return val>parse_num(rng[1:])
    if rng.startswith('<'): return val<parse_num(rng[1:])
    return True

def cap_match(rule_cd):
    if rule_cd is None: return True
    return rule_cd == '<3'

def match_rule(r, aci, card_scheme, is_credit, intracountry):
    if r['card_scheme']!=card_scheme: return False
    if r['account_type'] and 'R' not in r['account_type']: return False
    if not cap_match(r['capture_delay']): return False
    if r['merchant_category_code'] and mcc not in r['merchant_category_code']: return False
    if r['is_credit'] is not None and r['is_credit']!=is_credit: return False
    if r['intracountry'] is not None and bool(r['intracountry'])!=intracountry: return False
    if not in_range(fraud_rate, r['monthly_fraud_level']): return False
    if not in_range(total_vol, r['monthly_volume']): return False
    if r['aci'] and aci not in r['aci']: return False
    return True

df = pd.read_csv('data/payments.csv')
b_jan = df[(df['merchant']=='Belles_cookbook_store') & (df['day_of_year']<=31)]
fraud_tx = b_jan[b_jan['has_fraudulent_dispute']==True]

for target_aci in ['A','B','C','D','E','F','G']:
    total=0
    unmatched=0
    for _,tx in fraud_tx.iterrows():
        intracountry = tx['issuing_country']==tx['acquirer_country']
        matches=[]
        for r in fees:
            if match_rule(r, target_aci, tx['card_scheme'], bool(tx['is_credit']), intracountry):
                matches.append(r['fixed_amount'] + r['rate']*tx['eur_amount']/10000)
        if not matches:
            unmatched+=1
        else:
            total += min(matches)
    print(f"ACI {target_aci}: total_fee={total:.2f} unmatched_tx={unmatched}/{len(fraud_tx)}")
