# Compute monthly volume & fraud rate for Jan (Belles)
total_vol = df_jan['eur_amount'].sum()
fraud_vol = fraud['eur_amount'].sum()
fraud_rate = fraud_vol/total_vol*100
print('total_vol',total_vol,'fraud_rate%',fraud_rate)

def volume_match(rule, vol):
    v = rule.get('monthly_volume')
    if v is None: return True
    # parse
    if v.endswith('m'): pass
    # ranges like '100k-1m'
    def parse(s):
        s=s.replace('k','e3').replace('m','e6')
        return float(s)
    if '-' in v:
        a,b = v.split('-')
        return parse(a)<=vol<=parse(b)
    if v.startswith('>'):
        return vol > parse(v[1:])
    if v.startswith('<'):
        return vol < parse(v[1:])
    return False

def fraud_match(rule, fr):
    v = rule.get('monthly_fraud_level')
    if v is None: return True
    def parse(s):
        return float(s.replace('%',''))
    if '-' in v:
        a,b = v.split('-')
        return parse(a)<=fr<=parse(b)
    if v.startswith('>'):
        return fr > parse(v[1:])
    if v.startswith('<'):
        return fr < parse(v[1:])
    return False

def capture_match(rule, cd):
    v = rule.get('capture_delay')
    if v is None: return True
    cd = int(cd) if cd.isdigit() else cd
    if isinstance(cd,int):
        if v=='immediate': return cd==0
        if v=='manual': return False
        if v.startswith('>'): return cd>int(v[1:])
        if v.startswith('<'): return cd<int(v[1:])
        if '-' in v:
            a,b=v.split('-'); return int(a)<=cd<=int(b)
    return False

def find_fee(scheme, aci, is_credit, intracountry):
    matches = []
    for r in fees:
        if r['card_scheme']!=scheme: continue
        if r.get('account_type') and len(r['account_type'])>0 and merchant_info['account_type'] not in r['account_type']: continue
        if r.get('merchant_category_code') and len(r['merchant_category_code'])>0 and merchant_info['merchant_category_code'] not in r['merchant_category_code']: continue
        if r.get('is_credit') is not None and r['is_credit']!=is_credit: continue
        if r.get('aci') and len(r['aci'])>0 and aci not in r['aci']: continue
        if not volume_match(r, total_vol): continue
        if not fraud_match(r, fraud_rate): continue
        if not capture_match(r, merchant_info['capture_delay']): continue
        if r.get('intracountry') is not None and r['intracountry']!=intracountry: continue
        matches.append(r)
    return matches

# For each fraud txn, for each alternative ACI, compute fee
acis = ['A','B','C','D','E','F','G']
results = {a:0.0 for a in acis}
for _,row in fraud.iterrows():
    for a in acis:
        intr = row['issuing_country']==row['acquirer_country']
        ms = find_fee(row['card_scheme'], a, bool(row['is_credit']), intr)
        if not ms:
            # try both intracountry values
            ms = find_fee(row['card_scheme'], a, bool(row['is_credit']), not intr)
        if not ms:
            print('no match',row['card_scheme'],a); continue
        # take first (or min?)
        r = ms[0]
        fee = r['fixed_amount'] + r['rate']*row['eur_amount']/10000
        results[a]+=fee

for a,v in results.items():
    print(a, round(v,2))
