import json, pandas as pd
fees = json.load(open('data/fees.json'))

# Merchant properties for March 2023
account_type = 'R'
mcc = 5942
capture_delay = '1'  # need to map: 1 day -> '<3'
monthly_volume = 116436.32  # in 100k-1m range
fraud_rate = 10.25  # percent

def volume_match(rule_v, vol):
    if rule_v is None: return True
    # e.g. '100k-1m', '<100k', '>5m', '1m-5m', '5m-10m'
    r = rule_v.replace('k','e3').replace('m','e6')
    if r.startswith('<'):
        return vol < float(r[1:])
    if r.startswith('>'):
        return vol > float(r[1:])
    lo, hi = r.split('-')
    return float(lo) <= vol < float(hi)

def fraud_match(rule_f, f):
    if rule_f is None: return True
    r = rule_f.replace('%','')
    if r.startswith('<'):
        return f < float(r[1:])
    if r.startswith('>'):
        return f > float(r[1:])
    lo, hi = r.split('-')
    return float(lo) <= f < float(hi)

def capture_match(rule_c, delay):
    if rule_c is None: return True
    # delay is '1' day, integer 1
    d = int(delay)
    if rule_c == 'immediate':
        return d == 0
    if rule_c == 'manual':
        return False  # unknown
    if rule_c == '<3':
        return d < 3
    if rule_c == '3-5':
        return 3 <= d <=5
    if rule_c == '>5':
        return d > 5
    return False

applicable = []
for r in fees:
    if r['account_type'] and account_type not in r['account_type']:
        continue
    if r['merchant_category_code'] and mcc not in r['merchant_category_code']:
        continue
    if not capture_match(r['capture_delay'], capture_delay):
        continue
    if not volume_match(r['monthly_volume'], monthly_volume):
        continue
    if not fraud_match(r['monthly_fraud_level'], fraud_rate):
        continue
    applicable.append(r['ID'])

print(len(applicable))
print(applicable)
EOF"}

