import pandas as pd, json
df = pd.read_csv('data/payments.csv')
b = df[(df['merchant']=='Belles_cookbook_store') & (df['day_of_year']<=31)]
fraud = b[b['has_fraudulent_dispute']==True].copy()
with open('data/fees.json') as f: fees = json.load(f)

mcc = 5942
account_type = 'R'
monthly_volume = b['eur_amount'].sum()
fraud_rate = fraud['eur_amount'].sum()/b['eur_amount'].sum()*100

def match(rule, tx_aci, is_credit, card_scheme, intracountry):
    if rule['card_scheme'] != card_scheme: return False
    if rule['account_type'] and account_type not in rule['account_type']: return False
    if rule['capture_delay'] is not None and rule['capture_delay'] != '<3': return False
    if rule['monthly_fraud_level'] is not None:
        rng = rule['monthly_fraud_level']
        if '<' in rng:
            v=float(rng.replace('%','').replace('<',''))
            if not fraud_rate < v: return False
        elif '>' in rng:
            v=float(rng.replace('%','').replace('>',''))
            if not fraud_rate > v: return False
        else:
            lo,hi = rng.replace('%','').split('-')
            if not (float(lo) <= fraud_rate <= float(hi)): return False
    if rule['monthly_volume'] is not None:
        rng = rule['monthly_volume']
        def parse(x): return float(x.replace('k','000').replace('m','000000'))
        if '-' in rng and rng[0] not in '<>':
            lo,hi = rng.split('-')
            if not (parse(lo) <= monthly_volume <= parse(hi)): return False
        elif '>' in rng:
            if not monthly_volume > parse(rng.replace('>','')): return False
        elif '<' in rng:
            if not monthly_volume < parse(rng.replace('<','')): return False
    if rule['merchant_category_code'] and mcc not in rule['merchant_category_code']: return False
    if rule['is_credit'] is not None and rule['is_credit'] != is_credit: return False
    if rule['aci'] and tx_aci not in rule['aci']: return False
    if rule['intracountry'] is not None:
        if rule['intracountry'] != intracountry: return False
    return True

# Note: all fraud txns are US acquirer, EU issuing => intracountry=False, is_credit=True
# For each aci and each card_scheme, find matching rule
schemes = fraud['card_scheme'].unique()
print("Schemes:", schemes)
for aci in ['A','B','C','D','E','F','G']:
    print(f"\n=== ACI {aci} ===")
    for cs in schemes:
        matches = [r for r in fees if match(r, aci, True, cs, False)]
        if matches:
            for m in matches:
                print(f"  {cs}: fixed={m['fixed_amount']} rate={m['rate']} id={m['ID']}")
        else:
            print(f"  {cs}: NO MATCH")
EOF"}

